1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_MIN_YEARS = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const DEDUCTIBLE = 100;
23	
24	const INSURANCE_VALUES: Record<string, number> = {
25	  sword: 1000,
26	  amulet: 600,
27	  staff: 800,
28	  potion: 400,
29	  rune: 250,
30	  moonstone: 250,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	interface Item {
36	  type: string;
37	  cursed?: boolean;
38	  enchantment?: number;
39	}
40	
41	interface Damage {
42	  itemType: string;
43	  amount: number;
44	}
45	
46	interface Step {
47	  op: string;
48	  items?: Item[];
49	  policy?: number;
50	  incident?: {
51	    cause: string;
52	    damages: Damage[];
53	  };
54	}
55	
56	interface Scenario {
57	  customer: { yearsWithMHPCO: number };
58	  steps: Step[];
59	}
60	
61	function computeComponentPremium(items: Array<{ type: string }>): number {
62	  const counts = new Map<string, number>();
63	  for (const item of items) {
64	    if (COMPONENT_TYPES.has(item.type)) {
65	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
66	    }
67	  }
68	  let premium = 0;
69	  for (const [type, count] of counts) {
70	    if (count === BLOCK_SIZE) {
71	      premium += BLOCK_PREMIUM;
72	    } else {
73	      premium += count * (BASE_PREMIUMS[type] ?? 0);
74	    }
75	  }
76	  return premium;
77	}
78	
79	function computeItemSurcharge(item: Item): number {
80	  const basePremium = BASE_PREMIUMS[item.type] ?? 0;
81	  let surcharge = 0;
82	  if (item.cursed) {
83	    surcharge += basePremium * CURSE_SURCHARGE_RATE;
84	  }
85	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
86	    surcharge += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
87	  }
88	  return surcharge;
89	}
90	
91	function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number {
92	  const standardItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
93	  const standardBasePremium = standardItems.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
94	  const itemSurcharges = standardItems.reduce((sum, item) => sum + computeItemSurcharge(item), 0);
95	  const componentPremium = computeComponentPremium(items);
96	  const policyBase = standardBasePremium + componentPremium;
97	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
98	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
99	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
100	  return Math.ceil(policyBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
101	}
102	
103	interface Policy {
104	  items: Item[];
105	  insuranceSum: number;
106	  remainingCap: number;
107	}
108	
109	export function processScenario(scenario: Scenario): { results: unknown[] } {
110	  let quoteCount = 0;
111	  const policies = new Map<number, Policy>();
112	  const results = scenario.steps.map((step, index) => {
113	    if (step.op === "quote") {
114	      const items = step.items ?? [];
115	      const isFollowUp = quoteCount > 0;
116	      quoteCount++;
117	      const insuranceSum = items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
118	      policies.set(index, { items, insuranceSum, remainingCap: insuranceSum * 2 });
119	      return { premium: computeQuotePremium(items, scenario.customer, isFollowUp) };
120	    }
121	    if (step.op === "claim") {
122	      const policy = policies.get(step.policy!)!;
123	      const damages = step.incident!.damages;
124	      let totalPayout = 0;
125	      for (const damage of damages) {
126	        const payout = damage.amount - DEDUCTIBLE;
127	        totalPayout += Math.max(0, payout);
128	      }
129	      totalPayout = Math.min(totalPayout, policy.remainingCap);
130	      policy.remainingCap -= totalPayout;
131	      return { payout: totalPayout, remainingCap: policy.remainingCap };
132	    }
133	    return {};
134	  });
135	  return { results };
136	}
