103	interface Policy {
104	  items: Item[];
105	  insuranceSum: number;
106	  remainingCap: number;
107	}
108	
109	function computeClaimResult(policy: Policy, damages: Damage[]): { payout: number; remainingCap: number } {
110	  let totalPayout = 0;
111	  for (const damage of damages) {
112	    totalPayout += Math.max(0, damage.amount - DEDUCTIBLE);
113	  }
114	  totalPayout = Math.min(totalPayout, policy.remainingCap);
115	  policy.remainingCap -= totalPayout;
116	  return { payout: totalPayout, remainingCap: policy.remainingCap };
117	}
