119	export function processScenario(scenario: Scenario): { results: unknown[] } {
120	  let quoteCount = 0;
121	  const policies = new Map<number, Policy>();
122	  const results = scenario.steps.map((step, index) => {
123	    if (step.op === "quote") {
124	      const items = step.items ?? [];
125	      const isFollowUp = quoteCount > 0;
126	      quoteCount++;
127	      const insuranceSum = items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
128	      policies.set(index, { items, insuranceSum, remainingCap: insuranceSum * 2 });
129	      return { premium: computeQuotePremium(items, scenario.customer, isFollowUp) };
130	    }
131	    if (step.op === "claim") {
132	      return computeClaimResult(policies.get(step.policy!)!, step.incident!.damages);
133	    }
134	    return {};
135	  });
136	  return { results };
137	}
